module synchronous_ram (
	input clk,
	input we,
	input [3:0] read_addr,
	input [3:0] write_addr,
	input [7:0] din,
	output reg [7:0] dout);

	reg [7:0] mem [15:0];

	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
		if (we)
			mem[write_addr] <= din;
		dout <= mem[read_addr];
	end
endmodule
